CREATE OR REPLACE FUNCTION is_above_dept_avg(p_emp_id NUMBER) RETURN VARCHAR2 IS
  v_salary    employees.salary%TYPE;
  v_dept_id   employees.department_id%TYPE;
  v_avg_sal   NUMBER;
BEGIN
  SELECT salary, department_id INTO v_salary, v_dept_id
  FROM employees WHERE employee_id = p_emp_id;

  SELECT AVG(salary) INTO v_avg_sal
  FROM employees WHERE department_id = v_dept_id;

  IF v_salary > v_avg_sal THEN
    RETURN 'Above average';
  ELSE
    RETURN 'At or below average';
  END IF;
END;
/

