CREATE OR REPLACE PROCEDURE dept_stats(
  p_dept_id IN NUMBER,
  p_avg OUT NUMBER,
  p_min OUT NUMBER,
  p_max OUT NUMBER
) IS
BEGIN
  SELECT AVG(salary), MIN(salary), MAX(salary)
  INTO p_avg, p_min, p_max
  FROM employees WHERE department_id = p_dept_id;
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    p_avg := 0; p_min := 0; p_max := 0;
END;
/

SET SERVEROUTPUT ON;
DECLARE
  v_avg NUMBER;
  v_min NUMBER;
  v_max NUMBER;
BEGIN
  dept_stats(50, v_avg, v_min, v_max);
  DBMS_OUTPUT.PUT_LINE('Avg: ' || v_avg || ', Min: ' || v_min || ', Max: ' || v_max);
END;
/

