CREATE OR REPLACE PROCEDURE increase_salary (
  p_emp_id    IN NUMBER,
  p_percent   IN NUMBER
) IS
  v_current_salary sadok_employees.salary%TYPE;
  v_new_salary     sadok_employees.salary%TYPE;
BEGIN
  SELECT salary INTO v_current_salary
  FROM sadok_employees
  WHERE emp_id = p_emp_id;

  v_new_salary := v_current_salary * (1 + p_percent / 100);

  UPDATE sadok_employees
  SET salary = v_new_salary
  WHERE emp_id = p_emp_id;

  COMMIT;
  DBMS_OUTPUT.PUT_LINE('Salary updated from ' ||
    v_current_salary || ' to ' || v_new_salary);
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    DBMS_OUTPUT.PUT_LINE('Employee ' || p_emp_id || ' not found.');
  WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE('Error: ' || SQLERRM);
    ROLLBACK;
END increase_salary;
/

