  p_id    IN NUMBER,
  p_rate  IN NUMBER
) IS
  v_current table.col%TYPE;
BEGIN
  SELECT col INTO v_current FROM table WHERE id = p_id;
  UPDATE table SET col = v_current + (v_current * p_rate)
  WHERE id = p_id;
  COMMIT;
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    DBMS_OUTPUT.PUT_LINE('Not found.');
END;

