CREATE OR REPLACE TRIGGER trg_log_employee_changes
AFTER INSERT OR UPDATE OR DELETE ON sadok_employees
FOR EACH ROW
DECLARE
  v_log_id NUMBER;
BEGIN
  SELECT NVL(MAX(log_id), 0) + 1 INTO v_log_id FROM sadok_log;

  IF INSERTING THEN
    INSERT INTO sadok_log VALUES (v_log_id, 'INSERT', :NEW.emp_id, SYSDATE);
  ELSIF UPDATING THEN
    INSERT INTO sadok_log VALUES (v_log_id, 'UPDATE', :NEW.emp_id, SYSDATE);
  ELSIF DELETING THEN
    INSERT INTO sadok_log VALUES (v_log_id, 'DELETE', :OLD.emp_id, SYSDATE);
  END IF;
END trg_log_employee_changes;
/

