SET SERVEROUTPUT ON;
DECLARE
  v_sal  employees.salary%TYPE;
  v_grade VARCHAR2(10);
  v_cnt  NUMBER := 0;
BEGIN
  SELECT salary INTO v_sal FROM employees WHERE employee_id = 100;

  -- IF / ELSIF / ELSE
  IF v_sal > 10000 THEN
    v_grade := 'High';
  ELSIF v_sal > 5000 THEN
    v_grade := 'Medium';
  ELSE
    v_grade := 'Low';
  END IF;
  DBMS_OUTPUT.PUT_LINE('IF grade: ' || v_grade);

  -- CASE expression
  v_grade := CASE
    WHEN v_sal > 10000 THEN 'High'
    WHEN v_sal > 5000  THEN 'Medium'
    ELSE 'Low'
  END;
  DBMS_OUTPUT.PUT_LINE('CASE grade: ' || v_grade);

  -- WHILE loop
  WHILE v_cnt < 3 LOOP
    v_cnt := v_cnt + 1;
    DBMS_OUTPUT.PUT_LINE('WHILE: ' || v_cnt);
  END LOOP;

  -- LOOP EXIT WHEN
  v_cnt := 0;
  LOOP
    v_cnt := v_cnt + 1;
    DBMS_OUTPUT.PUT_LINE('LOOP EXIT WHEN: ' || v_cnt);
    EXIT WHEN v_cnt >= 2;
  END LOOP;

  -- FOR loop
  DBMS_OUTPUT.PUT_LINE('FOR loop:');
  FOR i IN 1..3 LOOP
    DBMS_OUTPUT.PUT_LINE('  i = ' || i);
  END LOOP;
END;
/

