      WHEN ZERO_DIVIDE THEN DBMS_OUTPUT.PUT_LINE('ZERO_DIVIDE OK');
      WHEN INVALID_NUMBER THEN DBMS_OUTPUT.PUT_LINE('INVALID_NUMBER OK');
    END;
  END;
BEGIN
  test_handler('NO_DATA_FOUND');
  test_handler('ZERO_DIVIDE');
  test_handler('INVALID_NUMBER');
