CREATE OR REPLACE FUNCTION emp_bonus (
  p_emp_id IN NUMBER,
  p_rate   IN NUMBER DEFAULT 0.1
) RETURN NUMBER IS
  v_sal employees.salary%TYPE;
BEGIN
  SELECT salary INTO v_sal FROM employees WHERE employee_id = p_emp_id;
  RETURN ROUND(v_sal * p_rate, 2);
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    RETURN 0;
END emp_bonus;
/

