  v_bonus := emp_bonus(101);
  DBMS_OUTPUT.PUT_LINE('Bonus for emp 101 (default rate): ' || v_bonus);

  v_bonus := emp_bonus(9999);
  DBMS_OUTPUT.PUT_LINE('Bonus for non-existent: ' || v_bonus);
END;
/

