  DBMS_OUTPUT.PUT_LINE('Hello, ' || v_fname || ' (Salary: ' || v_sal || ')');
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    DBMS_OUTPUT.PUT_LINE('Employee ' || p_emp_id || ' not found.');
END greet_employee;
/

SET SERVEROUTPUT ON;
BEGIN
  greet_employee(100);
  greet_employee(101);
  greet_employee(9999);
END;
/

