CREATE OR REPLACE TRIGGER trg_business_hours
BEFORE INSERT OR UPDATE OR DELETE ON sadok_employees
BEGIN
  IF TO_CHAR(SYSDATE, 'HH24') NOT BETWEEN '08' AND '18' THEN
    RAISE_APPLICATION_ERROR(-20020,
      'Changes allowed only between 08:00 and 18:00.');
  END IF;
END;
/

