SET SERVEROUTPUT ON;
DECLARE
  e_salary_too_low  EXCEPTION;
  e_salary_too_high EXCEPTION;
  e_bad_dept        EXCEPTION;
  PRAGMA EXCEPTION_INIT(e_bad_dept, -2291);

  v_sal   employees.salary%TYPE;
  v_count NUMBER;
BEGIN
  SELECT salary INTO v_sal FROM employees WHERE employee_id = 100;

  IF v_sal < 1000 THEN
    RAISE e_salary_too_low;
  ELSIF v_sal > 30000 THEN
    RAISE e_salary_too_high;
  ELSE
    DBMS_OUTPUT.PUT_LINE('Salary ' || v_sal || ' is within acceptable range.');
  END IF;

  SELECT COUNT(*) INTO v_count FROM departments WHERE department_id = 9999;
  IF v_count = 0 THEN
    RAISE_APPLICATION_ERROR(-20005, 'Department 9999 does not exist.');
  END IF;

EXCEPTION
  WHEN e_salary_too_low THEN
    DBMS_OUTPUT.PUT_LINE('Warning: Salary is below minimum threshold.');
  WHEN e_salary_too_high THEN
    DBMS_OUTPUT.PUT_LINE('Warning: Salary exceeds maximum threshold.');
  WHEN e_bad_dept THEN
    DBMS_OUTPUT.PUT_LINE('Foreign key violation: ' || SQLERRM);
  WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE('Other error: [' || SQLCODE || '] ' || SQLERRM);
END;
/

